from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST
from fastapi import FastAPI, Response

app = FastAPI()
REQUEST_COUNTER = Counter('model_requests_total', 'Total model requests')

@app.get('/predict')
def predict():
    REQUEST_COUNTER.inc()
    return {'prediction': 0}

@app.get('/metrics')
def metrics():
    data = generate_latest()
    return Response(content=data, media_type=CONTENT_TYPE_LATEST)

def check_model_health(metrics):
    if metrics['error_rate'] > 0.10:
        return True  # rollback due to high error rate
    if metrics['latency_ms'] > 200:
        return True  # rollback due to excessive latency
    return False

metrics = {'error_rate': 0.12, 'latency_ms': 150}
print(check_model_health(metrics))

