def pipeline_ready(checks):
    required_steps = ['tests', 'build', 'monitoring', 'security_scan']
    return all(checks.get(step, False) for step in required_steps)

checks = {'tests': True, 'build': True, 'monitoring': False, 'security_scan': True}
print(pipeline_ready(checks))
